#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define MAX_SESSIONS 1000
#define SESSION_ID_LENGTH 32
#define MAX_DATA_SIZE 256
#define DEFAULT_TIMEOUT 3600

typedef struct {
    char session_id[SESSION_ID_LENGTH + 1];
    char *data;
    time_t created_at;
    time_t last_accessed;
    time_t expires_at;
    int is_valid;
    int is_allocated;
} Session;

typedef struct {
    Session sessions[MAX_SESSIONS];
    int count;
} SessionCache;

SessionCache cache;

void init_cache() {
    memset(&cache, 0, sizeof(SessionCache));
    for (int i = 0; i < MAX_SESSIONS; i++) {
        cache.sessions[i].data = NULL;
        cache.sessions[i].is_valid = 0;
        cache.sessions[i].is_allocated = 0;
    }
}

void generate_session_id(char *session_id) {
    const char charset[] = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
    for (int i = 0; i < SESSION_ID_LENGTH; i++) {
        session_id[i] = charset[rand() % (sizeof(charset) - 1)];
    }
    session_id[SESSION_ID_LENGTH] = '\0';
}

int find_session_slot(const char *session_id) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (cache.sessions[i].is_allocated && 
            strcmp(cache.sessions[i].session_id, session_id) == 0) {
            return i;
        }
    }
    return -1;
}

int find_empty_slot() {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (!cache.sessions[i].is_allocated) {
            return i;
        }
    }
    
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (cache.sessions[i].is_allocated && !cache.sessions[i].is_valid) {
            return i;
        }
    }
    
    return -1;
}

char* create_session(const char *user_data, int timeout) {
    int slot = find_empty_slot();
    if (slot == -1) {
        return NULL;
    }
    
    Session *session = &cache.sessions[slot];
    
    if (session->is_allocated && !session->is_valid) {
        if (session->data) {
            free(session->data);
            session->data = NULL;
        }
    }
    
    if (!session->is_allocated) {
        generate_session_id(session->session_id);
        session->is_allocated = 1;
        cache.count++;
    }
    
    session->data = (char*)malloc(MAX_DATA_SIZE);
    if (!session->data) {
        return NULL;
    }
    
    strncpy(session->data, user_data, MAX_DATA_SIZE - 1);
    session->data[MAX_DATA_SIZE - 1] = '\0';
    
    time_t now = time(NULL);
    session->created_at = now;
    session->last_accessed = now;
    session->expires_at = now + (timeout > 0 ? timeout : DEFAULT_TIMEOUT);
    session->is_valid = 1;
    
    return session->session_id;
}

char* access_session(const char *session_id) {
    int slot = find_session_slot(session_id);
    if (slot == -1) {
        return NULL;
    }
    
    Session *session = &cache.sessions[slot];
    
    if (!session->is_valid) {
        return NULL;
    }
    
    time_t now = time(NULL);
    if (now > session->expires_at) {
        if (session->data) {
            free(session->data);
            session->data = NULL;
        }
        session->is_valid = 0;
        return NULL;
    }
    
    session->last_accessed = now;
    return session->data;
}

int invalidate_session(const char *session_id) {
    int slot = find_session_slot(session_id);
    if (slot == -1) {
        return 0;
    }
    
    Session *session = &cache.sessions[slot];
    
    if (session->data) {
        free(session->data);
        session->data = NULL;
    }
    
    session->is_valid = 0;
    
    return 1;
}

int reinitialize_session(const char *session_id, const char *user_data, int timeout) {
    int slot = find_session_slot(session_id);
    if (slot == -1) {
        return 0;
    }
    
    Session *session = &cache.sessions[slot];
    
    if (session->is_valid) {
        return 0;
    }
    
    session->data = (char*)malloc(MAX_DATA_SIZE);
    if (!session->data) {
        return 0;
    }
    
    strncpy(session->data, user_data, MAX_DATA_SIZE - 1);
    session->data[MAX_DATA_SIZE - 1] = '\0';
    
    time_t now = time(NULL);
    session->created_at = now;
    session->last_accessed = now;
    session->expires_at = now + (timeout > 0 ? timeout : DEFAULT_TIMEOUT);
    session->is_valid = 1;
    
    return 1;
}

void cleanup_expired_sessions() {
    time_t now = time(NULL);
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (cache.sessions[i].is_allocated && cache.sessions[i].is_valid) {
            if (now > cache.sessions[i].expires_at) {
                if (cache.sessions[i].data) {
                    free(cache.sessions[i].data);
                    cache.sessions[i].data = NULL;
                }
                cache.sessions[i].is_valid = 0;
            }
        }
    }
}

void print_session_info(const char *session_id) {
    int slot = find_session_slot(session_id);
    if (slot == -1) {
        printf("Session not found\n");
        return;
    }
    
    Session *session = &cache.sessions[slot];
    printf("Session ID: %s\n", session->session_id);
    printf("Valid: %s\n", session->is_valid ? "Yes" : "No");
    printf("Allocated: %s\n", session->is_allocated ? "Yes" : "No");
    if (session->is_valid) {
        printf("Data: %s\n", session->data ? session->data : "NULL");
        printf("Created: %ld\n", session->created_at);
        printf("Last Accessed: %ld\n", session->last_accessed);
        printf("Expires: %ld\n", session->expires_at);
    }
}

void destroy_cache() {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (cache.sessions[i].data) {
            free(cache.sessions[i].data);
            cache.sessions[i].data = NULL;
        }
    }
}

